 {"id":"bd-mblr.2.3.2","title":"Failure replay and minimization harness","description":"Provide replay/minimization tooling for failing fault scenarios so flakes and edge failures become actionable. Output: replay recipe and minimized failing case artifacts.","design":"Use iterative reduction over workload steps while continuously validating invariant breakage to avoid false minimization.","acceptance_criteria":"- Replay tooling can rerun a failing scenario from captured seed/profile/artifact bundle with deterministic output.
- Minimization reduces failing case complexity while preserving invariant violation.
- Output package includes minimized repro recipe and before/after evidence.","notes":"Critical for making rare reliability failures actionable instead of flaky noise.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-12T23:37:53.582745465Z","created_by":"ubuntu","updated_at":"2026-02-13T00:04:43.883864090Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2.3.2","depends_on_id":"bd-mblr.2.3","type":"parent-child","created_at":"2026-02-12T23:37:53.582745465Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.3.2","depends_on_id":"bd-mblr.2.3.1","type":"blocks","created_at":"2026-02-12T23:38:33.104941565Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.3.2","depends_on_id":"bd-mblr.5.4.1","type":"blocks","created_at":"2026-02-13T00:02:49.791561723Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.2.4","title":"Extension Integration on Real Storage Paths","description":"For JSON/FTS/RTREE/session/ext-misc features, add integration tests that execute against real file-backed storage and recovery paths (not only in-memory execution), including reopen and integrity checks.","design":"Treat extension paths as first-class product behavior: tests must validate storage durability and recovery semantics, not just API-level happy paths.","acceptance_criteria":"JSON/FTS/RTREE/session/ext-misc each have file-backed integration tests covering reopen, checkpoint/recovery, and integrity assertions; failures include reproducible fixtures and artifact links.","notes":"Do not accept extension coverage that only passes in-memory pathways when file-backed semantics differ. Structured-log schema conformance is enforced at shared logging gates after scenario implementation.","status":"closed","priority":1,"issue_type":"task","created_at":"2026-02-12T23:24:03.407710482Z","created_by":"ubuntu","updated_at":"2026-02-13T05:56:49.546817181Z","closed_at":"2026-02-13T05:56:49.546795450Z","close_reason":"Implemented 20 integration tests in ext_real_storage_test.rs covering all 6 extension crates (JSON, FTS5, FTS3, R-tree, Session, Misc) on file-backed storage paths. Tests verify data round-trips through store/close/reopen cycles using SQL Connection + extension crate APIs. All 20 tests pass.","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2.4","depends_on_id":"bd-mblr.1.3","type":"blocks","created_at":"2026-02-12T23:25:09.735055149Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.4","depends_on_id":"bd-mblr.2","type":"parent-child","created_at":"2026-02-12T23:24:03.407710482Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.3","title":"CI Quality Gate Enforcement","description":"Convert coverage, unit/integration no-mock validation, E2E logging quality, and flake governance into enforced CI gates with fail-fast feedback and minimal false positives.","design":"Gate only on requirements whose signals are already trustworthy and reproducible.","acceptance_criteria":"Coverage, unit shard, and no-mock critical-path gates enforced in CI; required E2E matrix and artifacts enforced; flake policy is active and auditable; gate failures surface deterministic repro metadata and diagnostic links.","notes":"Deferred intentionally for queue hygiene: this bead is a container/coordination umbrella, not a direct implementation lane. Work proceeds through its child tasks; reopen/close this bead during milestone rollup and completion review.","status":"deferred","priority":1,"issue_type":"epic","created_at":"2026-02-12T23:23:16.892658332Z","created_by":"ubuntu","updated_at":"2026-02-13T00:51:03.695081711Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.3","depends_on_id":"bd-mblr","type":"parent-child","created_at":"2026-02-12T23:23:16.892658332Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.3","depends_on_id":"bd-mblr.1","type":"blocks","created_at":"2026-02-12T23:25:06.866648047Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.3","depends_on_id":"bd-mblr.2","type":"blocks","created_at":"2026-02-12T23:25:07.117997399Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.3","depends_on_id":"bd-mblr.4","type":"blocks","created_at":"2026-02-12T23:25:07.374883058Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.3","depends_on_id":"bd-mblr.5","type":"blocks","created_at":"2026-02-12T23:25:07.632675093Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.3","depends_on_id":"bd-mblr.6","type":"blocks","created_at":"2026-02-13T00:02:09.595178181Z","created_by":"ubuntu","metadata":"{}","thread_id":""}],"comments":[{"id":1343,"issue_id":"bd-mblr.3","author":"Dicklesworthstone","text":"Detailed scope: convert evidence quality requirements into hard CI gates. Gate order matters: do not enforce thresholds before measurement and observability pipelines are stable; otherwise CI becomes noisy and bypass-prone.","created_at":"2026-02-12T23:26:03Z"}]}
